#!/usr/bin/env node
const ProxyChain = require('proxy-chain');
const chalk = require('chalk');
const child_process = require( 'child_process' );
const path = require( 'path' );
const HOME_DIR = require( 'os' ).homedir();
// const http = require( 'http' );

function untildify( /** @type {string} */ str ) {
    return str.replace( '~', HOME_DIR );
}

function getArgs() {
    const args = {
        _: /** @type {string[]} */( [] )
    };
    let argv = process.argv
        .slice( 2, process.argv.length );
    
    // separator is any string that consists of '-' only
    let separatorIdx = argv.findIndex( i => i.length > 0 && [ ...i ].findIndex( i2 => i2 !== '-' ) === -1 );
    if ( separatorIdx !== -1 ) {
        args._separateArgs = argv.slice( separatorIdx + 1 ).join( ' ' );
        argv = argv.slice( 0, separatorIdx );
    }
    
    argv.forEach( arg => {
            // long arg
            if ( arg.slice( 0, 2 ) === '--' ) {
                const kv = arg.split( '=' );
                const k = kv[ 0 ].slice( 2, kv[ 0 ].length );
                const v = kv.length > 1 ? kv[ 1 ] : true;
                args[ k ] = v;
            }
            // flags
            else if ( arg[ 0 ] === '-' ) {
                const flags = arg.slice( 1, arg.length ).split( '' );
                flags.forEach( flag => {
                    args[ flag ] = true;
                } );
            }
            // commands
            else {
                args._.push( arg );
            }
        } );
    return args;
}

/**
 * @param {string} command 
 * @param {{cwd?:string,exec?:boolean}} execOptions 
 */
async function exec( command, execOptions = undefined ) {
    if ( execOptions === undefined )
        execOptions = {};
    
    /** @type {import('child_process').ChildProcess} */
    let pr;
    if ( execOptions.exec )
        pr = child_process.exec( command, execOptions );
    else {
        // spawn cannot handle 'ls | wc -l'
        let args = command.split( ' ' ).filter( i => i !== '' );
        let cmd = args.shift();
        pr = child_process.spawn( cmd, args, execOptions );
    }
}

/**
 * @param {import('child_process').ChildProcess} pr 
 */
async function execProcess( pr ) {
    pr.stdout.on( 'data', data => {
        process.stdout.write( data.toString() );
    } );
    pr.stderr.on( 'data', data => {
        process.stderr.write( data.toString() );
    } );
    let res, rej;
    let prom = new Promise( function( resolve, reject ) {
        res = resolve;
        rej = reject;
    } );
    pr.on( 'close', ( code, signal ) => {
        //console.log( `child process exited with code ${code}` );
        if ( code === 0 ) {
            res();
        }
        else {
            rej( signal );
        }
    } );
    await prom;
}

const args = getArgs();

function help() {
    // @ts-ignore
    let pkjson = require( './package.json' );
    console.log();
    console.log( chalk.magentaBright( `pserve ${pkjson.version}` ) );
    console.log(  );
    console.log( 'Usage: pserve <port-number>' );
    console.log(  );
    console.log( 'Commands:' );
    console.log( '  launch chrome/chromium --addr=<proxy-server-addr> [--profile=<profile-directory>]' );
    console.log(  );
    console.log( 'Options:' );
    console.log( '  -h'.padEnd( 20 ), 'help' );
    console.log( '  -v'.padEnd( 20 ), 'version' );
    console.log(  );
}

async function main() {
    let cmd = args._[ 0 ];
    if ( cmd === 'launch' ) {
        let cmd1 = args._[1];
        if ( cmd1 === 'chrome' || cmd1 === 'chromium' ) {
            let addr = args.addr;
            let profile = args.profile || "~/.pserve-proxy-profile";
            profile = untildify( profile );
            // let profile = args.profile || "$HOME/proxy-profile";
            if ( addr ) {
                let command;
                if ( cmd1 == "chrome" )
                    command = "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";
                else if ( cmd1 === "chromium" )
                    command = "/Applications/Chromium.app/Contents/MacOS/Chromium";

                console.log( `launch ${cmd1}` );
                console.log( `  profile=${profile}` );
                console.log( `  addr=${addr}` );

                let pr = child_process.spawn( command, [
                    `--user-data-dir=${profile}`,
                    `--proxy-server=${addr}`
                ] );
                // await exec( script );
                await execProcess( pr );
            }
            else {
                console.log( 'Please specify address with --addr' );
            }
        }
    }
    else if ( args.h ) {
        help();
    }
    else if ( args.v || args.version ) {
        // @ts-ignore
        let pkjson = require( './package.json' );
        console.log( pkjson.version );
    }
    else {
        let port = parseInt(args._[0]);
        if ( port.toString() === args._[0] ) {
            if ( 1024 <= port && port <= 49151 ) {
                console.log(`pserve is starting on port ${port}`);

                // @ts-ignore
                const server = new ProxyChain.Server( { 
                    port: port, 
                    // verbose: true,
                        // Custom function to authenticate proxy requests and provide the URL to chained upstream proxy.
                    // It must return an object (or promise resolving to the object) with the following form:
                    // { requestAuthentication: Boolean, upstreamProxyUrl: String }
                    // If the function is not defined or is null, the server runs in simple mode.
                    // Note that the function takes a single argument with the following properties:
                    // * request      - An instance of http.IncomingMessage class with information about the client request
                    //                  (which is either HTTP CONNECT for SSL protocol, or other HTTP request)
                    // * username     - Username parsed from the Proxy-Authorization header. Might be empty string.
                    // * password     - Password parsed from the Proxy-Authorization header. Might be empty string.
                    // * hostname     - Hostname of the target server
                    // * port         - Port of the target server
                    // * isHttp       - If true, this is a HTTP request, otherwise it's a HTTP CONNECT tunnel for SSL
                    //                  or other protocols
                    // * connectionId - Unique ID of the HTTP connection. It can be used to obtain traffic statistics.
                    prepareRequestFunction: ({ request, username, password, hostname, port, isHttp, connectionId }) => {
                        /** @type {import('http').IncomingMessage} */
                        let r = request;
                        remoteAddrSet.add( r.socket.remoteAddress );
                        // console.log( r.socket.remoteAddress );
                        // console.log( 'prepare request' );
                        // console.dir( request );
                        return {
                            // Require clients to authenticate with username 'bob' and password 'TopSecret'
                            requestAuthentication: false,
                            // requestAuthentication: username !== 'bob' || password !== 'TopSecret',

                            // Sets up an upstream HTTP proxy to which all the requests are forwarded.
                            // If null, the proxy works in direct mode, i.e. the connection is forwarded directly
                            // to the target server. This field is ignored if "requestAuthentication" is true.
                            // upstreamProxyUrl: `http://username:password@proxy.example.com:3128`,

                            // If "requestAuthentication" is true, you can use the following property
                            // to define a custom error message instead of the default "Proxy credentials required"
                            // failMsg: 'Bad username or password, please try again.',
                        };
                    }
                });

                /** @type {Set<string>} */
                let remoteAddrSet = new Set();
                let totalStats =  {
                    // Number of bytes sent to client
                    srcTxMb: 0,
                    // Number of bytes received from client
                    srcRxMb: 0,
                    // Number of bytes sent to target server (proxy or website)
                    trgTxMb: 0,
                    // Number of bytes received from target server (proxy or website)
                    trgRxMb: 0,
                };
                let totalStatModified = false;

                // Emitted when HTTP connection is closed
                server.on('connectionClosed', ({ connectionId, stats }) => {
                    // console.log( 'closed' );
                    // console.dir( server.handlers[connectionId] );
                    totalStats.srcTxMb += stats.srcTxBytes / 1024 / 1024;
                    totalStats.srcRxMb += stats.srcRxBytes / 1024 / 1024;
                    totalStats.trgTxMb += stats.trgTxBytes / 1024 / 1024;
                    totalStats.trgRxMb += stats.trgRxBytes / 1024 / 1024;
                    totalStatModified = true;
                    // console.log(`Connection ${connectionId} closed`);
                    // console.dir(stats);
                });
                server.listen(() => {
                    console.log(`listening`);
                });

                setInterval(() => {
                    if ( totalStatModified ) {
                        totalStatModified = false;
                        console.dir( totalStats );
                        console.log( [...remoteAddrSet] );
                    }
                }, 60 * 1000 );
            }
            else {
                console.log( `Please specify port between 1024 and 49151` );
            }
        }
        else {
            help();
        }
    }
}

main();